import type { FoodMaster, FoodCategory, StorageType } from '@/types';

function makeFood(
  id: string,
  name: string,
  nameJa: string,
  aliases: string[],
  category: FoodCategory,
  storageOptions: StorageType[],
  defaultStorage: StorageType,
  rangeDaysByStorage: FoodMaster['rangeDaysByStorage'],
  defaultNotifyDaysByStorage: FoodMaster['defaultNotifyDaysByStorage'],
  tips: string[],
  note: string
): FoodMaster {
  return {
    id,
    name,
    nameJa,
    aliases,
    category,
    storageOptions,
    defaultStorage,
    rangeDaysByStorage,
    defaultNotifyDaysByStorage,
    tips,
    note,
  };
}

