export function getFoodById(id: string): FoodMaster | undefined {
  const aliasMap: Record<string, string> = { f83: 'f5', f84: 'f29' };
  const resolvedId = aliasMap[id] ?? id;
  return foods.find((f) => f.id === resolvedId);
}

export const FOOD_CATEGORIES: FoodCategory[] = [
  'dairy_eggs',
  'seafood_meat',
  'vegetables',
  'fruits',
  'bread_grains',
  'plant_protein',
  'condiments_pantry',
  'prepared_meals',
];

export function searchFoods(query: string): FoodMaster[] {
  const q = query.trim().toLowerCase();
  if (!q) return foods;
  return foods.filter((f) => {
    const nameMatch = f.name.toLowerCase().includes(q);
    const nameJaMatch = f.nameJa && f.nameJa.toLowerCase().includes(q);
    const aliasMatch = f.aliases.some((a) => a.toLowerCase().includes(q));
    return nameMatch || nameJaMatch || aliasMatch;
  });
}
